import { MakeLogicType, kea, key, listeners, path, props, reducers } from 'kea'
import { loaders } from 'kea-loaders'
import { router } from 'kea-router'

import api from 'lib/api'

import { isApiNotFound, loadErrorMessage } from '../lib/load-error'
import { phDebugQueryParams } from '../lib/ph-debug'
import { Task, type TaskUpsertProps } from '../types/taskTypes'
import { tasksLogic } from './tasksLogic'

export interface TaskLogicProps {
    taskId: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface taskLogicValues {
    task: Task | null
    taskError: string | null
    taskLoading: boolean
    taskNotFound: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface taskLogicActions {
    deleteTask: () => any
    deleteTaskFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    deleteTaskSuccess: (
        task: null,
        payload?: any
    ) => {
        task: null
        payload?: any
    }
    loadTask: () => any
    loadTaskFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadTaskSuccess: (
        task: Task | null,
        payload?: any
    ) => {
        task: Task | null
        payload?: any
    }
    runTask: () => any
    runTaskFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    runTaskSuccess: (
        task: Task,
        payload?: any
    ) => {
        task: Task
        payload?: any
    }
    updateTask: ({ data }: { data: TaskUpsertProps }) => {
        data: TaskUpsertProps
    }
    updateTaskFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    updateTaskSuccess: (
        task: Task,
        payload?: {
            data: TaskUpsertProps
        }
    ) => {
        task: Task
        payload?: {
            data: TaskUpsertProps
        }
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface taskLogicMeta {
    key: string
}

export type taskLogicType = MakeLogicType<taskLogicValues, taskLogicActions, TaskLogicProps, taskLogicMeta>

export const taskLogic = kea<taskLogicType>([
    path(['products', 'posthog_ai', 'frontend', 'logics', 'taskLogic']),
    props({} as TaskLogicProps),
    key((props) => props.taskId),
    loaders(({ props, values, actions }) => ({
        task: [
            null as Task | null,
            {
                loadTask: async () => {
                    try {
                        return await api.tasks.get(props.taskId, phDebugQueryParams())
                    } catch (errorObject) {
                        actions.loadTaskFailure(loadErrorMessage('', errorObject), errorObject)
                        return isApiNotFound(errorObject) ? null : values.task
                    }
                },
                runTask: async () => {
                    return await api.tasks.run(props.taskId)
                },
                deleteTask: async () => {
                    await api.tasks.delete(props.taskId)
                    tasksLogic.findAllMounted().forEach((logic) => logic.actions.loadTasks())
                    router.actions.push('/tasks')
                    return null
                },
                updateTask: async ({ data }: { data: TaskUpsertProps }) => {
                    const updatedTask = await api.tasks.update(props.taskId, data)
                    tasksLogic.findAllMounted().forEach((logic) => logic.actions.loadTasks())
                    return updatedTask
                },
            },
        ],
    })),
    reducers({
        taskNotFound: [
            false,
            {
                loadTask: () => false,
                loadTaskFailure: (_, { errorObject }) => isApiNotFound(errorObject),
            },
        ],
        taskError: [
            null as string | null,
            {
                loadTask: () => null,
                loadTaskFailure: (_, { error, errorObject }) =>
                    isApiNotFound(errorObject) ? null : loadErrorMessage(error, errorObject),
            },
        ],
    }),
    listeners(({ values }) => ({
        loadTaskSuccess: () => {
            if (values.task) {
                tasksLogic.findMounted()?.actions.updateTask(values.task)
            }
        },
        runTaskSuccess: () => {
            if (values.task) {
                tasksLogic.findMounted()?.actions.updateTask(values.task)
            }
        },
        updateTaskSuccess: () => {
            if (values.task) {
                tasksLogic.findMounted()?.actions.updateTask(values.task)
            }
        },
    })),
])
